verb :room_roster() rxd {
  let rows = [];
  for item in present_actors(this) {
    // Presence rows are runtime-maintained, but projected snapshots can lag a
    // recycled/disconnected actor. Treat stale refs like absent occupants.
    let is_actor = false;
    try { is_actor = valid(item) && isa(item, $actor); } except err { is_actor = false; }
    if (is_actor) {
      let idle = idle_seconds(item);
      let row = { id: item, name: item.name, presence: presence_status(item) };
      if (idle != null) { row["idle_seconds"] = idle; }
      rows = rows + [row];
    }
  }
  return rows;
}
